SELECT ?person ?personLabel WHERE {
  wd:Q761383 wdt:P138 ?person.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?animal ?animalLabel WHERE {
  ?operation wdt:P710 wd:Q625657;
             wdt:P1612 ?animal.
  ?animal wdt:P31 wd:Q16521.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?founder ?founderLabel WHERE {
  wd:Q46633 wdt:P112 ?founder.
  ?founder wdt:P102 ?party.
  ?party wdt:P361 wd:Q637459.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?work ?workLabel WHERE {
  ?author wdt:P50 ?work .
  ?work wdt:P1433 ?publication .
  ?work wdt:P31 wd:Q7725634 . # instance of manga
  ?work wdt:P921 wd:Q482980 . # about middle school students
  ?author wdt:P50 ?hunterXHunter .
  ?hunterXHunter wdt:P50 wd:Q729937 . # author of Hunter x Hunter (Yoshihiro Togashi)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?stockExchange ?stockExchangeLabel WHERE {
  wd:Q81230 wdt:P414 ?stockExchange.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT DISTINCT ?work ?workLabel WHERE {
  ?work wdt:P50 ?author.
  ?author wdt:P50 ?authorEntity.
  ?work wdt:P6333 ?broaderWork.
  ?broaderWork rdfs:label ?broaderWorkLabel.
  FILTER(LANG(?broaderWorkLabel) = "en").
  FILTER(?broaderWorkLabel != "The Witcher").
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}

SELECT ?state WHERE {
  wd:Q47446968 wdt:P27 ?state .
  wd:Q47446969 wdt:P27 ?state .
}

SELECT ?school ?schoolLabel WHERE {
  wd:Q231121 wdt:P69 ?school.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "[AUTO_LANGUAGE],en". }
}
